import (
	"math/bits"
)

type FenwickTree struct {
	n   int
	tree []int
}

func NewFenwickTree(n int) *FenwickTree {
	return &FenwickTree{
		n:   n,
		tree: make([]int, n+1),
	}
}

func (ft *FenwickTree) Update(i int, delta int) {
	for ; i <= ft.n; i += i & -i {
		ft.tree[i] += delta
	}
}

func (ft *FenwickTree) Query(i int) int {
	res := 0
	for ; i > 0; i -= i & -i {
		res += ft.tree[i]
	}
	return res
}

func computeDepth(x int64) int {
	depth := 0
	for x != 1 {
		pop := bits.OnesCount(x)
		x = int64(pop)
		depth++
	}
	return depth
}

func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)
	depths := make([]int, n)
	for i := 0; i < n; i++ {
		depths[i] = computeDepth(nums[i])
	}

	ft := make([]*FenwickTree, 6)
	for d := 0; d < 6; d++ {
		ft[d] = NewFenwickTree(n)
	}

	for i := 0; i < n; i++ {
		d := depths[i]
		if d < 6 {
			ft[d].Update(i+1, 1)
		}
	}

	var answer []int64
	for _, q := range queries {
		if q[0] == 1 {
			l := int(q[1])
			r := int(q[2])
			k := int(q[3])
			if k >= 6 {
				answer = append(answer, 0)
				continue
			}
			sum_r := ft[k].Query(r + 1)
			sum_l_1 := ft[k].Query(l)
			res := sum_r - sum_l_1
			answer = append(answer, int64(res))
		} else {
			idx := int(q[1])
			val := q[2]
			old_d := depths[idx]
			new_d := computeDepth(val)
			ft[old_d].Update(idx+1, -1)
			nums[idx] = val
			ft[new_d].Update(idx+1, 1)
			depths[idx] = new_d
		}
	}
	return answer
}
